using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 peer-reviewed papers and leads the university's AI research lab. She received her Ph.D. from MIT.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Rodriguez", Title = "Associate Professor of Mathematics", Bio = "Dr. Rodriguez focuses on applied mathematics and statistics. He has 15 years of teaching experience and has won multiple teaching excellence awards.", Email = "j.rodriguez@university.edu" },
            new() { Id = 3, Name = "Prof. Emily Watson", Title = "Professor of English Literature", Bio = "Prof. Watson is an expert in Victorian literature and creative writing. She is the author of three critically acclaimed novels and a frequent contributor to literary journals.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Park", Title = "Associate Professor of Physics", Bio = "Dr. Park researches quantum mechanics and particle physics. He previously worked at CERN and brings real-world experimental experience to the classroom.", Email = "m.park@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Thompson", Title = "Professor of History", Bio = "Dr. Thompson specializes in American history and political movements. She has authored two award-winning books on civil rights history.", Email = "l.thompson@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Associate Professor of Biology", Bio = "Dr. Kim is a molecular biologist with expertise in genetics and genomics. His research on gene therapy has been featured in leading scientific journals.", Email = "r.kim@university.edu" },
        };

        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study the theory and practice of computation, software design, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Explore pure and applied mathematics, statistics, and quantitative reasoning." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Develop skills in writing, literary analysis, and communication across genres." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Investigate the fundamental laws governing matter, energy, and the universe." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examine the events, cultures, and ideas that have shaped human civilization." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Study living organisms from molecular biology to ecosystems and evolution." },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to computer science covering programming fundamentals, data structures, algorithms, and computational thinking. Students will learn Python and complete hands-on projects.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, CourseCode = "CS 210", Title = "Data Structures and Algorithms", Description = "Study fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques. Includes analysis of time and space complexity.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 1, IsFeatured = false, MaxEnrollment = 60, CurrentEnrollment = 55 },
            new() { Id = 3, CourseCode = "CS 350", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search algorithms, knowledge representation, machine learning, neural networks, and natural language processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Tech Building 110", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 45, CurrentEnrollment = 42 },

            // Mathematics
            new() { Id = 4, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, continuity, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 101", DepartmentId = 2, InstructorId = 2, IsFeatured = true, MaxEnrollment = 150, CurrentEnrollment = 130 },
            new() { Id = 5, CourseCode = "MATH 215", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Math Building 203", DepartmentId = 2, InstructorId = 2, IsFeatured = false, MaxEnrollment = 80, CurrentEnrollment = 65 },
            new() { Id = 6, CourseCode = "MATH 310", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, regression analysis, and Bayesian inference.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Math Building 105", DepartmentId = 2, InstructorId = 2, IsFeatured = false, MaxEnrollment = 90, CurrentEnrollment = 72 },

            // English
            new() { Id = 7, CourseCode = "ENG 101", Title = "English Composition", Description = "Develop academic writing skills through essays, research papers, and peer review. Emphasis on clear argumentation and proper citation.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Humanities Hall 120", DepartmentId = 3, InstructorId = 3, IsFeatured = false, MaxEnrollment = 30, CurrentEnrollment = 28 },
            new() { Id = 8, CourseCode = "ENG 220", Title = "Victorian Literature", Description = "Survey of major Victorian novels, poetry, and essays. Authors include Dickens, the Brontës, Tennyson, and Eliot. Explores themes of industrialization and social change.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", Location = "Humanities Hall 210", DepartmentId = 3, InstructorId = 3, IsFeatured = true, MaxEnrollment = 35, CurrentEnrollment = 20 },
            new() { Id = 9, CourseCode = "ENG 315", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing. Students produce original works and participate in peer critique sessions.", Credits = 3, Schedule = "Wed 4:00–6:50 PM", Location = "Humanities Hall 105", DepartmentId = 3, InstructorId = 3, IsFeatured = false, MaxEnrollment = 20, CurrentEnrollment = 18 },

            // Physics
            new() { Id = 10, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly lab sessions covering experimental methods and data analysis.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Physics Lab 101", DepartmentId = 4, InstructorId = 4, IsFeatured = false, MaxEnrollment = 100, CurrentEnrollment = 88 },
            new() { Id = 11, CourseCode = "PHYS 301", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, measurement theory, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Physics Lab 303", DepartmentId = 4, InstructorId = 4, IsFeatured = true, MaxEnrollment = 30, CurrentEnrollment = 22 },

            // History
            new() { Id = 12, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and turning points in world history from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Liberal Arts 200", DepartmentId = 5, InstructorId = 5, IsFeatured = false, MaxEnrollment = 120, CurrentEnrollment = 95 },
