@page "/courses"
@rendermode InteractiveServer
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject NavigationManager Nav

<PageTitle>Browse Courses</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or keyword..."
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in Catalog.GetAllDepartments())
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(SearchTerm, SelectedDepartmentId);
}

<p class="text-muted">Showing @results.Count course(s)</p>

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Code</th>
            <th>Title</th>
            <th>Department</th>
            <th>Credits</th>
            <th>Schedule</th>
            <th>Availability</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var course in results)
        {
            var spotsLeft = course.MaxEnrollment - course.CurrentEnrollment;
            <tr>
                <td><strong>@course.CourseCode</strong></td>
                <td>@course.Title</td>
                <td>@Catalog.GetDepartmentName(course.DepartmentId)</td>
                <td>@course.Credits</td>
                <td>@course.Schedule</td>
                <td>
                    @if (spotsLeft <= 5)
                    {
                        <span class="badge bg-warning text-dark">@spotsLeft spots left</span>
                    }
                    else
                    {
                        <span class="badge bg-success">@spotsLeft spots left</span>
                    }
                </td>
                <td>
                    <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria. Try adjusting your filters.</div>
}

@code {
    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }

    protected override void OnInitialized()
    {
        if (DepartmentId.HasValue)
        {
            SelectedDepartmentId = DepartmentId.Value;
        }
    }

    private void ClearFilters()
    {
        SearchTerm = string.Empty;
        SelectedDepartmentId = 0;
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="courses" class="btn btn-primary">Back to Course Catalog</a>
}
else
{
    var department = Catalog.GetDepartment(course.DepartmentId);
    var instructor = Catalog.GetInstructor(course.InstructorId);
    var spotsLeft = course.MaxEnrollment - course.CurrentEnrollment;

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>
    <span class="badge bg-secondary mb-3">@department?.Name</span>

    <div class="row mt-3">
        <div class="col-md-8">
            <h3>Description</h3>
            <p>@course.Description</p>

            <h3>Schedule &amp; Location</h3>
            <table class="table">
                <tr>
                    <th style="width: 150px;">Schedule</th>
                    <td>@course.Schedule</td>
                </tr>
                <tr>
                    <th>Location</th>
                    <td>@course.Location</td>
                </tr>
                <tr>
                    <th>Credits</th>
                    <td>@course.Credits</td>
                </tr>
                <tr>
                    <th>Availability</th>
                    <td>
                        @if (spotsLeft <= 5)
                        {
                            <span class="text-warning fw-bold">@spotsLeft of @course.MaxEnrollment spots remaining</span>
                        }
                        else
                        {
                            <span>@spotsLeft of @course.MaxEnrollment spots remaining</span>
                        }
                    </td>
                </tr>
            </table>
        </div>

        <div class="col-md-4">
            @if (instructor is not null)
            {
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@instructor.Name</h6>
                        <p class="card-text"><em>@instructor.Title</em></p>
                        <p class="card-text">@instructor.Bio</p>
                        <p class="card-text"><small class="text-muted">📧 @instructor.Email</small></p>
                    </div>
                </div>
            }

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Request Enrollment</a>
            </div>
        </div>
    </div>
}

