@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject EnrollmentService Enrollment

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive a confirmation once your request is processed.</p>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="Request" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                <InputText id="studentName" class="form-control" @bind-Value="Request.StudentName" />
                <ValidationMessage For="() => Request.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                <InputText id="studentId" class="form-control" @bind-Value="Request.StudentId" placeholder="e.g., STU-12345" />
                <ValidationMessage For="() => Request.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="email" class="form-label">Email Address</label>
                <InputText id="email" class="form-control" @bind-Value="Request.Email" placeholder="student@university.edu" />
                <ValidationMessage For="() => Request.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                <InputSelect id="courseId" class="form-select" @bind-Value="Request.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in Catalog.GetAllCourses())
                    {
                        <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr)</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Request.CourseId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="notes" class="form-label">Additional Notes</label>
                <InputTextArea id="notes" class="form-control" rows="3" @bind-Value="Request.Notes" />
                <ValidationMessage For="() => Request.Notes" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Request { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Request.CourseId == 0)
        {
            Request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Enrollment.Submit(Request);
        Nav.NavigateTo($"enroll/confirmation?courseId={Request.CourseId}&studentName={Uri.EscapeDataString(Request.StudentName)}");
    }

    [Inject]
    private NavigationManager Nav { get; set; } = default!;
}

